# ==================== URL 短链核心测试 ====================

class TestURLValidation:
    """URL 验证测试"""

    @pytest.mark.parametrize(
        "url,should_be_valid",
        [
            ("https://www.baidu.com", True),
            ("http://example.com/path", True),
            ("https://github.com/pytorch/pytorch", True),
            ("", False),  # 空 URL
            ("abc", False),  # 没有 scheme
            ("ftp://example.com", False),  # 不支持的 scheme
            ("http://", False),  # 没有域名
            ("a" * 3000, False),  # 过长
        ],
    )
    def test_validate_url(self, url, should_be_valid):
        """测试 URL 验证（参数化）"""
        result = _validate_url(url)

        if should_be_valid:
            assert isinstance(result, Ok)
            assert result.ok_value == url.strip()
        else:
            assert isinstance(result, Err)


class TestShortCodeValidation:
    """短码验证测试"""

    @pytest.mark.parametrize(
        "short_code,should_be_valid",
