        if should_be_valid:
            assert isinstance(result, Ok)
        else:
            assert isinstance(result, Err)


class TestBase62Encoding:
    """Base62 编码/解码测试"""

    @pytest.mark.parametrize(
        "num,expected_encoded",
        [
            (0, "0"),
            (1, "1"),
            (10, "A"),
            (61, "z"),
            (62, "10"),
            (1000, "G8"),
        ],
    )
    def test_base62_encode(self, num, expected_encoded):
        """测试 Base62 编码（参数化）"""
        encoded = _base62_encode(num)
        assert encoded == expected_encoded

    @pytest.mark.parametrize(
        "num",
        [0, 1, 10, 61, 62, 100, 1000, 999999],
    )
    def test_base62_roundtrip(self, num):
        """测试 Base62 编码/解码往返（参数化）"""
        encoded = _base62_encode(num)
        decoded = _base62_decode(encoded)
        assert decoded == num


class TestURLShortener:
    """URL 短链服务测试"""

    @pytest.fixture
    def shortener(self):
        """创建 URLShortener 实例"""
        return URLShortener()

    @pytest.mark.parametrize(
        "url",
        [
            "https://www.baidu.com",
            "https://github.com/pytorch/pytorch",
            "https://docs.python.org/3/library/asyncio.html",
        ],
    )
    def test_shorten_valid_url(self, shortener, url):
        """测试缩短有效 URL（参数化）"""
        result = shortener.shorten(url)

        assert isinstance(result, Ok)
        short_code = result.ok_value
        assert len(short_code) >= 4
        assert len(short_code) <= 10

    @pytest.mark.parametrize(
        "url",
        [
            "",
            "abc",
            "ftp://example.com",
        ],
    )
    def test_shorten_invalid_url(self, shortener, url):
        """测试缩短无效 URL（参数化）"""
        result = shortener.shorten(url)
        assert isinstance(result, Err)

    def test_shorten_duplicate_url(self, shortener):
        """测试重复缩短同一 URL（应返回相同短码）"""
        url = "https://www.baidu.com"

        result1 = shortener.shorten(url)
        result2 = shortener.shorten(url)

        assert isinstance(result1, Ok)
        assert isinstance(result2, Ok)
        assert result1.ok_value == result2.ok_value

    def test_restore_valid_short_code(self, shortener):
        """测试还原有效短码"""
        url = "https://www.baidu.com"

        # 先缩短
        shorten_result = shortener.shorten(url)
        assert isinstance(shorten_result, Ok)
        short_code = shorten_result.ok_value

        # 再还原
        restore_result = shortener.restore(short_code)
        assert isinstance(restore_result, Ok)
        assert restore_result.ok_value == url

    @pytest.mark.parametrize(
        "short_code",
        [
            "",
            "ab",
            "a" * 20,
            "abc#def",
            "ValidCode123",  # 有效格式但不存在
        ],
    )
    def test_restore_invalid_short_code(self, shortener, short_code):
        """测试还原无效短码（参数化）"""
        result = shortener.restore(short_code)
        assert isinstance(result, Err)


# ==================== HTTP 客户端测试 ====================

@pytest.fixture
def mock_transport_success():
    """成功响应的 Mock"""
    def handler(request: httpx.Request) -> httpx.Response:
        return httpx.Response(status_code=HTTP_OK)
    return httpx.MockTransport(handler)


@pytest.fixture
def mock_transport_retryable():
    """前 2 次失败，第 3 次成功"""
    call_count = {"count": 0}

    def handler(request: httpx.Request) -> httpx.Response:
        call_count["count"] += 1
        if call_count["count"] < 3:
            return httpx.Response(status_code=HTTP_INTERNAL_SERVER_ERROR)
        return httpx.Response(status_code=HTTP_OK)
    return httpx.MockTransport(handler)


@pytest_asyncio.fixture
