class TestHTTPClient:
    """HTTP 客户端测试"""

    @pytest.mark.asyncio
    async def test_check_url_success(self, http_client_success):
        """测试 URL 可达性检查成功"""
        result = await http_client_success.check_url_reachability("https://example.com")

        assert isinstance(result, Ok)
        assert result.ok_value is True

    @pytest.mark.asyncio
    @pytest.mark.parametrize(
        "max_attempts,should_succeed",
        [
            (1, False),  # 重试 1 次，不够
            (2, False),  # 重试 2 次，不够
            (3, True),   # 重试 3 次，成功
            (5, True),   # 重试 5 次，成功
        ],
    )
    async def test_retry_mechanism(self, mock_transport_retryable, max_attempts, should_succeed):
        """测试重试机制（参数化）"""
        client = HTTPClient()
        client._client = httpx.AsyncClient(transport=mock_transport_retryable)

        result = await client._request_with_retry(
            "GET",
            "https://example.com",
            max_attempts=max_attempts,
            backoff_base=0.01,  # 加速测试
            max_wait=0.1,
        )

        if should_succeed:
            assert isinstance(result, Ok)
        else:
            assert isinstance(result, Err)

        await client.close()


# ==================== 配置管理测试 ====================

class TestConfigManager:
    """配置管理器测试"""

    @pytest.fixture
    def temp_config_file(self, tmp_path):
        """临时配置文件路径"""
        return str(tmp_path / "test_config.toml")

    def test_create_default_config(self, temp_config_file):
        """测试创建默认配置文件"""
        manager = ConfigManager(temp_config_file)
        result = manager.create_default_config()

        assert isinstance(result, Ok)
        assert result.ok_value.exists()

    def test_load_config(self, temp_config_file):
        """测试加载配置文件"""
        manager = ConfigManager(temp_config_file)

        # 先创建
        create_result = manager.create_default_config()
        assert isinstance(create_result, Ok)

        # 再加载
        load_result = manager.load()
        assert isinstance(load_result, Ok)

        config = load_result.ok_value
        assert isinstance(config, AppConfig)
        assert config.service.service_name == "url-shortener"

    def test_load_nonexistent_config(self, temp_config_file):
        """测试加载不存在的配置文件（应创建默认配置）"""
        manager = ConfigManager(temp_config_file)
        result = manager.load()

        # 应该自动创建默认配置并加载成功
        assert isinstance(result, Ok)


# ==================== 运行测试 ====================

if __name__ == "__main__":
    pytest.main([__file__, "-v", "--tb=short"])
